import { useRef, useState } from "react";
import ChartCard from "./ChartCard";
import KPICard from "./KPICard";
import InsightPanel from "./InsightPanel";
import VoicePanel from "./VoicePanel";

function loadH2C() {
  return new Promise((res, rej) => {
    if (window.html2canvas) { res(window.html2canvas); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
    s.onload = () => res(window.html2canvas);
    s.onerror = rej;
    document.head.appendChild(s);
  });
}

async function captureEl(el, scale = 2) {
  const h2c = await loadH2C();
  return h2c(el, {
    backgroundColor: "#05050f",
    scale,
    useCORS: true,
    allowTaint: true,
    logging: false,
    scrollX: 0,
    scrollY: 0,
    windowWidth: el.scrollWidth,
    windowHeight: el.scrollHeight,
  });
}

export default function DashboardScreen({ data, sessionId, colorSchema, onReset, sqlQueries }) {
  const { dashboard_title, charts, insights, summary, total_kpis_generated } = data;
  const exportRef  = useRef(null);
  const [exporting, setExporting]   = useState(false);
  const [exportType, setExportType] = useState("");
  const [showMenu, setShowMenu]     = useState(false);
  const [showSQL, setShowSQL]       = useState(false);
  const [activeTab, setActiveTab]   = useState("charts");

  const voiceCtx = charts.map(c => ({ kpi:c.kpi, chart_type:c.chart_type, data:c.data.slice(0,20) }));

  // ── PNG export ──────────────────────────────────────────────────────────
  const exportPNG = async () => {
    setShowMenu(false); setExporting(true); setExportType("png");
    try {
      const canvas = await captureEl(exportRef.current);
      const a = document.createElement("a");
      a.download = `${dashboard_title.replace(/\s+/g,"_")}.png`;
      a.href = canvas.toDataURL("image/png", 1.0);
      a.click();
    } catch(e) { alert("PNG failed: " + e.message); }
    finally { setExporting(false); setExportType(""); }
  };

  // ── PDF — professional, no blank pages ─────────────────────────────────
  const exportPDF = async () => {
    setShowMenu(false); setExporting(true); setExportType("pdf");
    try {
      const canvas  = await captureEl(exportRef.current, 1.6);
      const imgData = canvas.toDataURL("image/png", 0.92);
      const date    = new Date().toLocaleDateString("en-US", { year:"numeric", month:"long", day:"numeric" });

      // Build per-insight HTML blocks
      const insightBlocks = insights.map((ins, i) => `
        <div class="ic" style="page-break-inside:avoid;">
          <div class="ic-head">
            <div class="ic-num">${String(i+1).padStart(2,"0")}</div>
            <div class="ic-kpi">${ins.kpi || ""}</div>
          </div>
          ${ins.descriptive ? `
          <div class="ic-row">
            <div class="ic-lbl"><span class="ic-emoji">📊</span> What happened</div>
            <div class="ic-txt">${ins.descriptive}</div>
          </div>` : ""}
          ${ins.diagnostic ? `
          <div class="ic-row">
            <div class="ic-lbl"><span class="ic-emoji">🔍</span> Why it happened</div>
            <div class="ic-txt">${ins.diagnostic}</div>
          </div>` : ""}
          ${ins.prescriptive ? `
          <div class="ic-row">
            <div class="ic-lbl"><span class="ic-emoji">💡</span> What to do</div>
            <div class="ic-txt">${ins.prescriptive}</div>
          </div>` : ""}
        </div>
      `).join("");

      const pw = window.open("", "_blank");
      if (!pw) { alert("Allow popups to export PDF."); setExporting(false); return; }

      pw.document.write(`<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8"/>
<title>${dashboard_title} — Talking BI Report</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin:0; padding:0; }
  body { font-family:'Space Grotesk',sans-serif; background:#fff; color:#1e1e3f; font-size:13px; }

  /* ── Page setup: no margins, content fills the page ── */
  @page { margin:0; size:A4 portrait; }
  @media print {
    html, body { -webkit-print-color-adjust:exact; print-color-adjust:exact; }
    .no-print { display:none !important; }
  }

  /* ── COVER PAGE ──────────────────────────────────────────── */
  .cover {
    width:210mm; height:297mm;
    display:flex; flex-direction:column;
    background:linear-gradient(150deg, #05050f 0%, #0c0620 55%, #050d1a 100%);
    padding:56px 64px;
    page-break-after:always;
    position:relative; overflow:hidden;
  }
  /* Decorative circles */
  .cover::before {
    content:''; position:absolute; top:-120px; right:-120px;
    width:480px; height:480px; border-radius:50%;
    background:radial-gradient(circle, rgba(124,58,237,0.18) 0%, transparent 65%);
    pointer-events:none;
  }
  .cover::after {
    content:''; position:absolute; bottom:-80px; left:40px;
    width:320px; height:320px; border-radius:50%;
    background:radial-gradient(circle, rgba(6,182,212,0.1) 0%, transparent 65%);
    pointer-events:none;
  }
  /* Grid lines */
  .cover-grid { position:absolute; inset:0; pointer-events:none; }
  .cover-grid-line { position:absolute; left:0; right:0; height:1px; background:rgba(124,58,237,0.06); }

  .brand { display:flex; align-items:center; gap:14px; margin-bottom:auto; position:relative; z-index:1; }
  .brand-icon { width:46px; height:46px; background:rgba(124,58,237,0.15); border:1.5px solid rgba(124,58,237,0.4); border-radius:14px; display:flex; align-items:center; justify-content:center; font-size:22px; }
  .brand-name { font-size:22px; font-weight:700; color:#fff; }
  .brand-name span { color:#a855f7; }

  .cover-body { flex:1; display:flex; flex-direction:column; justify-content:center; padding:48px 0 32px; position:relative; z-index:1; }
  .cover-eyebrow { font-size:10px; font-weight:700; color:#a855f7; letter-spacing:0.2em; text-transform:uppercase; margin-bottom:20px; }
  .cover-title { font-size:54px; font-weight:700; color:#fff; line-height:1.1; letter-spacing:-1.5px; margin-bottom:14px; }
  .cover-sub { font-size:17px; color:rgba(255,255,255,0.4); font-weight:300; margin-bottom:52px; letter-spacing:0.01em; }
  .cover-bar { width:60px; height:3px; background:linear-gradient(90deg, #7c3aed, #06b6d4); border-radius:2px; margin-bottom:52px; }
  .cover-stats { display:flex; gap:52px; }
  .cover-stat-n { font-size:44px; font-weight:700; color:#a855f7; letter-spacing:-1.5px; display:block; line-height:1; }
  .cover-stat-l { font-size:11px; color:rgba(255,255,255,0.3); text-transform:uppercase; letter-spacing:0.1em; margin-top:8px; }

  .cover-foot { padding-top:28px; border-top:1px solid rgba(255,255,255,0.06); display:flex; justify-content:space-between; position:relative; z-index:1; }
  .cover-foot p { font-size:11px; color:rgba(255,255,255,0.2); }

  /* ── DASHBOARD PAGE ──────────────────────────────────────── */
  .dash-page {
    width:210mm; min-height:297mm;
    background:#05050f;
    page-break-after:always;
    display:flex; flex-direction:column;
  }
  .dash-header {
    background:#0a0a1a; padding:20px 32px;
    border-bottom:1px solid rgba(124,58,237,0.2);
    display:flex; justify-content:space-between; align-items:center;
    flex-shrink:0;
  }
  .dash-header h2 { font-size:16px; font-weight:700; color:#e8e8ff; }
  .dash-header p  { font-size:11px; color:#7878aa; margin-top:3px; }
  .dash-badge { padding:5px 14px; background:rgba(124,58,237,0.12); border:1px solid rgba(124,58,237,0.25); border-radius:20px; color:#a855f7; font-size:11px; font-weight:600; }
  .dash-img { width:100%; display:block; flex:1; object-fit:contain; object-position:top; }

  /* ── INSIGHTS PAGE ──────────────────────────────────────── */
  .insights-page {
    width:210mm;
    background:#fff;
    padding:52px 60px 80px;
    page-break-before:always;
  }
  .insights-header {
    display:flex; justify-content:space-between; align-items:flex-start;
    padding-bottom:28px; border-bottom:2px solid #ede9f8; margin-bottom:36px;
  }
  .insights-title { font-size:30px; font-weight:700; color:#1e1e3f; margin-bottom:6px; }
  .insights-sub   { font-size:13px; color:#7878aa; }
  .insights-meta  { font-size:11px; color:#b0b0d0; text-align:right; line-height:1.9; }

  /* Summary box */
  .summary {
    background:linear-gradient(135deg, #7c3aed 0%, #06b6d4 100%);
    border-radius:16px; padding:28px 32px; margin-bottom:36px;
  }
  .summary h3 { font-size:10px; font-weight:700; letter-spacing:0.15em; text-transform:uppercase; color:rgba(255,255,255,0.6); margin-bottom:12px; }
  .summary p  { font-size:14.5px; color:#fff; line-height:1.85; }

  /* Section heading */
  .sec-head { font-size:11px; font-weight:700; color:#b0b0d0; text-transform:uppercase; letter-spacing:0.1em; margin-bottom:20px; padding-bottom:10px; border-bottom:1px solid #f0edf9; }

  /* Insight card */
  .ic {
    background:#faf9ff; border:1px solid #ede9f8;
    border-left:3px solid #7c3aed;
    border-radius:12px; padding:20px 24px; margin-bottom:18px;
  }
  .ic-head    { display:flex; align-items:flex-start; gap:12px; margin-bottom:16px; padding-bottom:12px; border-bottom:1px solid #ede9f8; }
  .ic-num     { font-size:11px; font-weight:700; color:#a855f7; background:rgba(124,58,237,0.08); border:1px solid rgba(124,58,237,0.15); border-radius:6px; padding:4px 8px; flex-shrink:0; }
  .ic-kpi     { font-size:14px; font-weight:600; color:#1e1e3f; line-height:1.3; }
  .ic-row     { display:flex; gap:16px; margin-bottom:12px; }
  .ic-row:last-child { margin-bottom:0; }
  .ic-lbl     { font-size:10px; font-weight:700; color:#b0b0d0; width:140px; flex-shrink:0; text-transform:uppercase; letter-spacing:0.05em; padding-top:2px; display:flex; align-items:flex-start; gap:5px; }
  .ic-emoji   { font-size:11px; }
  .ic-txt     { font-size:12.5px; color:#2d2d5e; line-height:1.75; }

  /* Page footer */
  .page-foot {
    background:#f8f7ff; border-top:1px solid #ede9f8;
    padding:14px 60px; display:flex; justify-content:space-between;
    font-size:10.5px; color:#b0b0d0; margin-top:auto;
  }
</style>
</head>
<body>

<!-- ══ COVER PAGE ══════════════════════════════════════════════════════════ -->
<div class="cover">
  <div class="cover-grid">
    ${[0,20,40,60,80].map(p=>`<div class="cover-grid-line" style="top:${p}%"></div>`).join("")}
  </div>

  <div class="brand">
    <div class="brand-icon">📊</div>
